from __future__ import annotations

import csv
import io
import json
from abc import ABC, abstractmethod
from dataclasses import dataclass, asdict
from enum import Enum
from typing import Iterable, Protocol


# ---------- Domain types ----------

class ItemType(str, Enum):
    A = "A"
    B = "B"


class Status(str, Enum):
    HIGH = "high"
    ADJUSTED = "adjusted"
    NORMAL = "normal"
    DISCOUNTED = "discounted"
    SKIP = "skip"
    VALIDATED = "validated"
    ERROR = "error"


@dataclass(frozen=True)
class Item:
    id: str
    value: float
    type: str | None = None

    @classmethod
    def from_dict(cls, raw: dict) -> "Item":
        return cls(
            id=raw["id"],
            value=float(raw.get("value", 0)),
            type=raw.get("type"),
        )


@dataclass(frozen=True)
class Result:
    id: str
    val: float
    status: Status

    def to_dict(self) -> dict:
        return {"id": self.id, "val": self.val, "status": self.status.value}


# ---------- Configuration ----------

@dataclass(frozen=True)
class FastModeConfig:
    """Explicit, named configuration instead of opaque boolean flags."""
    apply_type_a_markup: bool = False   # was flag1
    keep_high_values_unadjusted: bool = True  # was flag2
    skip_unknown_types: bool = False    # was (flag1 and flag2) for unknown types

    # Business constants that were hidden as magic numbers
    type_a_markup: float = 1.10
    type_b_discount: float = 0.95
    high_value_threshold: float = 100.0
    high_value_adjustment: float = 0.90


# ---------- Processors (Strategy pattern) ----------

class Processor(Protocol):
    def process(self, item: Item) -> Result | None: ...


class FastProcessor:
    def __init__(self, config: FastModeConfig | None = None):
        self.config = config or FastModeConfig()

    def process(self, item: Item) -> Result | None:
        if item.type == ItemType.A.value:
            return self._process_type_a(item)
        if item.type == ItemType.B.value:
            return self._process_type_b(item)
        return self._process_unknown(item)

    def _process_type_a(self, item: Item) -> Result:
        cfg = self.config
        val = item.value * cfg.type_a_markup if cfg.apply_type_a_markup else item.value

        if val <= cfg.high_value_threshold:
            return Result(item.id, val, Status.NORMAL)
        if cfg.keep_high_values_unadjusted:
            return Result(item.id, val, Status.HIGH)
        return Result(item.id, val * cfg.high_value_adjustment, Status.ADJUSTED)

    def _process_type_b(self, item: Item) -> Result:
        return Result(item.id, item.value * self.config.type_b_discount, Status.DISCOUNTED)

    def _process_unknown(self, item: Item) -> Result | None:
        if self.config.skip_unknown_types:
            return Result(item.id, 0, Status.SKIP)
        return None  # silently drop — explicit None makes this visible


class CarefulProcessor:
    def process(self, item: Item) -> Result:
        try:
            if item.value < 0:
                raise ValueError("negative value")
            return Result(item.id, item.value, Status.VALIDATED)
        except (ValueError, TypeError):
            return Result(item.id, 0, Status.ERROR)


# ---------- Serializers (Strategy pattern) ----------

class Serializer(ABC):
    @abstractmethod
    def serialize(self, results: list[Result]) -> str | list[Result]: ...


class JSONSerializer(Serializer):
    def serialize(self, results: list[Result]) -> str:
        return json.dumps([r.to_dict() for r in results])


class CSVSerializer(Serializer):
    def serialize(self, results: list[Result]) -> str:
        buf = io.StringIO()
        writer = csv.writer(buf)
        for r in results:
            writer.writerow([r.id, r.val, r.status.value])
        return buf.getvalue().rstrip("\n")


class RawSerializer(Serializer):
    def serialize(self, results: list[Result]) -> list[Result]:
        return results


# ---------- Orchestrator ----------

class Pipeline:
    def __init__(self, processor: Processor, serializer: Serializer):
        self.processor = processor
        self.serializer = serializer

    def run(self, data: Iterable[dict]):
        results: list[Result] = []
        for raw in data:
            item = Item.from_dict(raw)
            result = self.processor.process(item)
            if result is not None:
                results.append(result)
        return self.serializer.serialize(results)


# ---------- Thin backwards-compatible facade (optional) ----------

def process(data, mode, flag1=False, flag2=True, output_type="json"):
    """Preserves the original public signature for existing callers."""
    if mode == "fast":
        processor: Processor = FastProcessor(
            FastModeConfig(
                apply_type_a_markup=flag1,
                keep_high_values_unadjusted=flag2,
                skip_unknown_types=(flag1 and flag2),
            )
        )
    elif mode == "careful":
        processor = CarefulProcessor()
    else:
        raise ValueError(f"Unknown mode: {mode}")

    serializers = {
        "json": JSONSerializer(),
        "csv": CSVSerializer(),
        "raw": RawSerializer(),
    }
    serializer = serializers.get(output_type, RawSerializer())
